"""Member module - Represents a library member with encapsulated state."""from ..config.constants import MAX_BORROW_LIMITclass Member:    """    Represents a library member.    Attributes:        name (str): Full name of the member        member_id (str): Unique member identifier        email (str): Contact email        phone (str): Contact phone number (optional)        address (str): Physical address (optional)    """    def __init__(self, name, member_id, email, phone="", address=""):        self.name = name        self.member_id = member_id        self.email = email        self.phone = phone        self.address = address        # Private attributes (encapsulated)        self._borrowed_books = []  # List of borrowed book ISBNs        self._fines_owed = 0.0        self._is_active = True    # ========================================================================    # Borrowing Operations    # ========================================================================    def can_borrow(self):        """        Check if the member is eligible to borrow books.        Returns:            tuple: (is_eligible: bool, reason: str)        """        if not self._is_active:            return False, "Member account is inactive"        if self._fines_owed >= 50.00:  # MAX_FINE_BEFORE_SUSPENSION            return False, f"Member owes ${self._fines_owed:.2f} in fines"        if len(self._borrowed_books) >= MAX_BORROW_LIMIT:            return False, f"Member has reached maximum borrow limit ({MAX_BORROW_LIMIT} books)"        return True, "Eligible"    def borrow_book(self, book_isbn):        """        Record a book borrowing.        Args:            book_isbn (str): ISBN of the borrowed book        Returns:            bool: True if borrowing recorded successfully        """        can_borrow, _ = self.can_borrow()        if not can_borrow:            return False        if book_isbn not in self._borrowed_books:            self._borrowed_books.append(book_isbn)            return True        return False    def return_book(self, book_isbn):        """        Record a book return.        Args:            book_isbn (str): ISBN of the returned book        Returns:            bool: True if return recorded successfully        """        if book_isbn in self._borrowed_books:            self._borrowed_books.remove(book_isbn)            return True        return False    # ========================================================================    # Fine Management    # ========================================================================    def add_fine(self, amount):        """Add a fine to the member's account."""        if amount > 0:            self._fines_owed += amount    def pay_fine(self, amount):        """        Pay part or all of fines owed.        Returns:            float: Actual amount paid (cannot exceed balance)        """        if amount <= 0:            return 0.0        if amount > self._fines_owed:            amount = self._fines_owed        self._fines_owed -= amount        return amount    # ========================================================================    # Accessor Methods (Defensive Copying)    # ========================================================================    def get_borrowed_books(self):        """Return a copy of the borrowed books list."""        return self._borrowed_books.copy()    def get_borrowed_count(self):        """Return the number of currently borrowed books."""        return len(self._borrowed_books)    def get_fines_owed(self):        """Return the current fines owed."""        return self._fines_owed    def is_active(self):        """Return whether the member account is active."""        return self._is_active    def deactivate(self):        """Deactivate the member account."""        self._is_active = False    def activate(self):        """Activate the member account."""        self._is_active = True    # ========================================================================    # Display    # ========================================================================    def get_display_info(self):        """Return a formatted string with member details."""        status = "Active" if self._is_active else "Inactive"        info = f"Member: {self.name} (ID: {self.member_id})\n"        info += f"  Email: {self.email} | Phone: {self.phone}\n"        info += f"  Status: {status} | Books Borrowed: {len(self._borrowed_books)}/{MAX_BORROW_LIMIT}\n"        info += f"  Fines Owed: ${self._fines_owed:.2f}"        return info